/// Globs (gitignore syntax) that, when present and NOT already ignored, indicate a
/// likely secret leaking into AI context. Used by `llmignore scan`.
pub const SENSITIVE_PATTERNS: &[(&str, &str)] = &[
    (
        ".env",
        "Environment file - commonly holds API keys and DB passwords",
    ),
    (
        ".env.*",
        "Environment file - commonly holds API keys and DB passwords",
    ),
    ("*.pem", "Private key / certificate"),
    ("*.key", "Private key"),
    ("*.p12", "PKCS#12 keystore"),
    ("*.pfx", "PKCS#12 keystore"),
    ("id_rsa", "SSH private key"),
    ("id_dsa", "SSH private key"),
    ("id_ecdsa", "SSH private key"),
    ("id_ed25519", "SSH private key"),
    ("*.ppk", "PuTTY private key"),
    (".npmrc", "npm config - may contain auth tokens"),
    (".pypirc", "PyPI config - may contain credentials"),
    (".netrc", "netrc - stores login credentials"),
    (".htpasswd", "HTTP auth password file"),
    ("credentials.*", "Credentials file"),
    ("secrets.*", "Secrets file"),
    ("*.secret", "Secret file"),
    ("service-account*.json", "GCP service account key"),
    ("*.keystore", "Java keystore"),
];
